class Solution {
    public int[] evenOddBit(int n) {
        int even = 0, odd = 0;
        for (int i = 0; i < 10; i++) {
            int mask = 1 << i;
            if ((n & mask) != 0) {
                if (i % 2 == 0) {
                    even++;
                } else {
                    odd++;
                }
            }
        }
        return new int[]{even, odd};
    }
}

